569 // See if this min/max intrinsic always picks it's one specific operand.
570 // If not, check whether we can canonicalize signed minmax into unsigned version
571 static bool processMinMaxIntrinsic(MinMaxIntrinsic *MM, LazyValueInfo *LVI) {
572   CmpInst::Predicate Pred = CmpInst::getNonStrictPredicate(MM->getPredicate());
573   ConstantRange LHS_CR = LVI->getConstantRangeAtUse(MM->getOperandUse(0),
574                                                     /*UndefAllowed*/ false);
575   ConstantRange RHS_CR = LVI->getConstantRangeAtUse(MM->getOperandUse(1),
576                                                     /*UndefAllowed*/ false);
577   if (LHS_CR.icmp(Pred, RHS_CR)) {
578     ++NumMinMax;
579     MM->replaceAllUsesWith(MM->getLHS());
580     MM->eraseFromParent();
581     return true;
582   }
583   if (RHS_CR.icmp(Pred, LHS_CR)) {
584     ++NumMinMax;
585     MM->replaceAllUsesWith(MM->getRHS());
586     MM->eraseFromParent();
587     return true;
588   }
589 
590   if (MM->isSigned() &&
591       ConstantRange::areInsensitiveToSignednessOfICmpPredicate(LHS_CR,
592                                                                RHS_CR)) {
593     ++NumSMinMax;
594     IRBuilder<> B(MM);
595     MM->replaceAllUsesWith(B.CreateBinaryIntrinsic(
596         MM->getIntrinsicID() == Intrinsic::smin ? Intrinsic::umin
597                                                 : Intrinsic::umax,
598         MM->getLHS(), MM->getRHS()));
599     MM->eraseFromParent();
600     return true;
601   }
602 
603   return false;
